const input = readline();

let acc = 0;

for (const char of input) {
    let value;

    if (char >= '0' && char <= '9') {
        value = Number(char);
    } else {
        value = char.charCodeAt(0) - 55; // A=10 ... Z=35
    }

    if ('AEIOU'.includes(char)) {
        acc = acc ^ value;
    } else {
        acc = (acc * 31 + value) % 1000;
    }
}

const result = acc.toString().padStart(3, '0');
console.log(result);
